#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin — Created: 2026-03-27
set -euo pipefail

# Scaffold .expect/ directory for /ork:expect
# Usage: bash init.sh [project_dir]
# Idempotent — will not overwrite existing config.yaml

PROJECT_DIR="${1:-.}"
EXPECT_DIR="${PROJECT_DIR}/.expect"
PKG_FILE="${PROJECT_DIR}/package.json"

# ── Auto-detect framework, port, name from package.json ───
read_pkg() {
  if [[ ! -f "${PKG_FILE}" ]]; then
    echo "unknown 3000 my-project"
    return
  fi
  python3 -c "
import json, re
try:
    pkg = json.load(open('${PKG_FILE}'))
    deps = {**pkg.get('dependencies', {}), **pkg.get('devDependencies', {})}
    fw = 'nextjs-app' if 'next' in deps else \
         'remix' if 'remix' in deps else \
         'sveltekit' if '@sveltejs/kit' in deps else \
         'vite' if 'vite' in deps else 'unknown'
    dev = pkg.get('scripts', {}).get('dev', '')
    m = re.search(r'(?:--port|-p)\s+(\d+)', dev)
    port = m.group(1) if m else '3000'
    name = pkg.get('name', 'my-project')
    print(f'{fw} {port} {name}')
except:
    print('unknown 3000 my-project')
" 2>/dev/null || echo "unknown 3000 my-project"
}

# ── Main ──────────────────────────────────────────────────
read -r FRAMEWORK PORT PKG_NAME <<< "$(read_pkg)"
BASE_URL="http://localhost:${PORT}"

mkdir -p "${EXPECT_DIR}/flows" "${EXPECT_DIR}/snapshots"

# Guard: do not overwrite existing config
if [[ -f "${EXPECT_DIR}/config.yaml" ]]; then
  echo "{\"created\":false,\"reason\":\"config.yaml already exists\",\"framework\":\"${FRAMEWORK}\",\"base_url\":\"${BASE_URL}\"}" >&2
  exit 0
fi

# Write config.yaml
cat > "${EXPECT_DIR}/config.yaml" <<YAML
# .expect/config.yaml — generated by /ork:expect --init
# project: ${PKG_NAME}
version: 1

base_url: "${BASE_URL}"
framework: "${FRAMEWORK}"  # auto-detected

# Auth profile (if your app requires login)
# auth_profile: "default"

# Route map overrides (auto-detected routes merged with these)
route_map: {}

# Patterns to ignore in diff scan
ignore_patterns:
  - "*.lock"
  - "*.log"
  - "node_modules/**"
  - "dist/**"
  - "build/**"
YAML

# Write .gitignore
cat > "${EXPECT_DIR}/.gitignore" <<'GI'
fingerprints.json
reports/
screenshots/
recordings/
GI

echo "{\"created\":true,\"framework\":\"${FRAMEWORK}\",\"base_url\":\"${BASE_URL}\"}"
